def match(pattern, text):
    node, _ = _parse_alt(pattern, 0)

    def done(p):
        return p == len(text)

    return _match(node, text, 0, done)


def _parse_alt(pattern, i):
    branches = []
    node, i = _parse_seq(pattern, i)
    branches.append(node)
    while i < len(pattern) and pattern[i] == '|':
        i += 1
        node, i = _parse_seq(pattern, i)
        branches.append(node)
    if len(branches) == 1:
        return branches[0], i
    return ('alt', branches), i


def _parse_seq(pattern, i):
    terms = []
    while i < len(pattern) and pattern[i] not in '|)':
        node, i = _parse_term(pattern, i)
        terms.append(node)
    if len(terms) == 1:
        return terms[0], i
    return ('concat', terms), i


def _parse_term(pattern, i):
    atom, i = _parse_atom(pattern, i)
    if i < len(pattern) and pattern[i] in '*+?':
        q = pattern[i]
        i += 1
        if q == '*':
            atom = ('star', atom)
        elif q == '+':
            atom = ('plus', atom)
        else:
            atom = ('opt', atom)
    return atom, i


def _parse_atom(pattern, i):
    c = pattern[i]
    if c == '(':
        i += 1
        node, i = _parse_alt(pattern, i)
        i += 1  # skip ')'
        return node, i
    elif c == '[':
        return _parse_class(pattern, i)
    elif c == '.':
        return ('any',), i + 1
    else:
        return ('char', c), i + 1


def _parse_class(pattern, i):
    i += 1  # skip '['
    negated = False
    if pattern[i] == '^':
        negated = True
        i += 1
    chars = set()
    while pattern[i] != ']':
        c = pattern[i]
        if i + 2 < len(pattern) and pattern[i + 1] == '-' and pattern[i + 2] != ']':
            for o in range(ord(c), ord(pattern[i + 2]) + 1):
                chars.add(chr(o))
            i += 3
        else:
            chars.add(c)
            i += 1
    i += 1  # skip ']'
    return ('class', negated, chars), i


def _match(node, text, pos, cont):
    t = node[0]
    if t == 'char':
        if pos < len(text) and text[pos] == node[1]:
            return cont(pos + 1)
        return False
    elif t == 'any':
        if pos < len(text):
            return cont(pos + 1)
        return False
    elif t == 'class':
        if pos < len(text):
            inset = text[pos] in node[2]
            if node[1]:
                inset = not inset
            if inset:
                return cont(pos + 1)
        return False
    elif t == 'concat':
        nodes = node[1]

        def match_seq(idx, p):
            if idx == len(nodes):
                return cont(p)
            return _match(nodes[idx], text, p, lambda np: match_seq(idx + 1, np))

        return match_seq(0, pos)
    elif t == 'alt':
        for branch in node[1]:
            if _match(branch, text, pos, cont):
                return True
        return False
    elif t == 'star':
        sub = node[1]

        def try_star(p):
            def after(np):
                if np == p:
                    return False
                return try_star(np)

            if _match(sub, text, p, after):
                return True
            return cont(p)

        return try_star(pos)
    elif t == 'plus':
        sub = node[1]

        def after(np):
            return _match(('star', sub), text, np, cont)

        return _match(sub, text, pos, after)
    elif t == 'opt':
        sub = node[1]
        if _match(sub, text, pos, cont):
            return True
        return cont(pos)
    return False
